sys_script.script:
(function executeRule(current, previous) {
    var bloodBank = current.getValue('blood_bank');
    var bloodGroup = current.getValue('blood_group');

    if (bloodBank && bloodGroup) {
        var gr = new GlideRecord('x_1920732_lifeli_0_blood_inventory');
        gr.addQuery('blood_bank', bloodBank);
        gr.addQuery('blood_group', bloodGroup);
        gr.query();

        if (gr.hasNext()) {
            gs.addErrorMessage('Inventory for this blood group already exists for this Blood Bank. Please update the existing record instead.');
            current.setAbortAction(true);
        }
    }
})(current, previous);
